import os
import uuid
import time
import hashlib
import logging
from datetime import datetime
from urllib.parse import urlparse

import boto3
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC
from PIL import Image
import redis

# Configuration
app = Flask(__name__)

AWS_REGION = os.environ.get("AWS_REGION", "us-east-1")
S3_BUCKET = os.environ.get("S3_BUCKET", "screenshot-thumbnails")
S3_PREFIX = os.environ.get("S3_PREFIX", "screenshots/")
REDIS_HOST = os.environ.get("REDIS_HOST", "localhost")
REDIS_PORT = int(os.environ.get("REDIS_PORT", 6379))
CACHE_TTL = int(os.environ.get("CACHE_TTL", 86400))  # 24 hours
CHROME_DRIVER_PATH = os.environ.get("CHROME_DRIVER_PATH", "/usr/bin/chromedriver")
CHROME_BINARY_PATH = os.environ.get("CHROME_BINARY_PATH", "/usr/bin/google-chrome")
SCREENSHOT_WIDTH = int(os.environ.get("SCREENSHOT_WIDTH", 1280))
SCREENSHOT_HEIGHT = int(os.environ.get("SCREENSHOT_HEIGHT", 960))
THUMBNAIL_WIDTH = int(os.environ.get("THUMBNAIL_WIDTH", 600))
THUMBNAIL_HEIGHT = int(os.environ.get("THUMBNAIL_HEIGHT", 400))
PAGE_LOAD_TIMEOUT = int(os.environ.get("PAGE_LOAD_TIMEOUT", 30))
TEMP_DIR = os.environ.get("TEMP_DIR", "/tmp/screenshots")
API_KEY = os.environ.get("API_KEY", "")
MAX_URL_LENGTH = 2048
ALLOWED_SCHEMES = {"http", "https"}
BLOCKED_HOSTS = {"localhost", "127.0.0.1", "0.0.0.0", "169.254.169.254", "metadata.google.internal"}

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Initialize AWS S3 client
s3_client = boto3.client("s3", region_name=AWS_REGION)

# Initialize Redis for caching
try:
    redis_client = redis.Redis(host=REDIS_HOST, port=REDIS_PORT, db=0, decode_responses=True)
    redis_client.ping()
    REDIS_AVAILABLE = True
    logger.info("Redis connection established")
except (redis.ConnectionError, redis.RedisError):
    redis_client = None
    REDIS_AVAILABLE = False
    logger.warning("Redis not available, caching disabled")

# Ensure temp directory exists
os.makedirs(TEMP_DIR, exist_ok=True)


def validate_url(url: str) -> tuple[bool, str]:
    """Validate and sanitize the input URL."""
    if not url:
        return False, "URL is required"
    
    if len(url) > MAX_URL_LENGTH:
        return False, f"URL exceeds maximum length of {MAX_URL_LENGTH} characters"
    
    try:
        parsed = urlparse(url)
    except Exception:
        return False, "Invalid URL format"
    
    if parsed.scheme not in ALLOWED_SCHEMES:
        return False, f"URL scheme must be one of: {', '.join(ALLOWED_SCHEMES)}"
    
    if not parsed.netloc:
        return False, "URL must have a valid hostname"
    
    hostname = parsed.hostname
    if hostname in BLOCKED_HOSTS:
        return False, "Access to this host is not allowed"
    
    # Block private IP ranges
    try:
        import ipaddress
        ip = ipaddress.ip_address(hostname)
        if ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_reserved:
            return False, "Access to private/reserved IP addresses is not allowed"
    except ValueError:
        # Not an IP address, it's a hostname - that's fine
        pass
    
    return True, ""


def generate_url_hash(url: str) -> str:
    """Generate a consistent hash for a URL to use as cache key."""
    return hashlib.sha256(url.strip().lower().encode()).hexdigest()


def get_cached_screenshot(url_hash: str) -> str | None:
    """Check if a screenshot already exists in cache."""
    if not REDIS_AVAILABLE:
        return None
    
    try:
        cached_url = redis_client.get(f"screenshot:{url_hash}")
        if cached_url:
            # Verify the S3 object still exists
            s3_key = redis_client.get(f"screenshot_key:{url_hash}")
            if s3_key:
                try:
                    s3_client.head_object(Bucket=S3_BUCKET, Key=s3_key)
                    logger.info(f"Cache hit for URL hash: {url_hash}")
                    return cached_url
                except s3_client.exceptions.ClientError:
                    # Object doesn't exist anymore, invalidate cache
                    redis_client.delete(f"screenshot:{url_hash}")
                    redis_client.delete(f"screenshot_key:{url_hash}")
    except redis.RedisError as e:
        logger.warning(f"Redis error during cache lookup: {e}")
    
    return None


def set_cached_screenshot(url_hash: str, s3_url: str, s3_key: str):
    """Store screenshot URL in cache."""
    if not REDIS_AVAILABLE:
        return
    
    try:
        redis_client.setex(f"screenshot:{url_hash}", CACHE_TTL, s3_url)
        redis_client.setex(f"screenshot_key:{url_hash}", CACHE_TTL, s3_key)
        logger.info(f"Cached screenshot for URL hash: {url_hash}")
    except redis.RedisError as e:
        logger.warning(f"Redis error during cache set: {e}")


def create_chrome_driver() -> webdriver.Chrome:
    """Create and configure a headless Chrome WebDriver instance."""
    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-dev-shm-usage")
    chrome_options.add_argument("--disable-gpu")
    chrome_options.add_argument("--disable-extensions")
    chrome_options.add_argument("--disable-plugins")
    chrome_options.add_argument(f"--window-size={SCREENSHOT_WIDTH},{SCREENSHOT_HEIGHT}")
    chrome_options.add_argument("--hide-scrollbars")
    chrome_options.add_argument("--disable-notifications")
    chrome_options.add_argument("--disable-popup-blocking")
    chrome_options.add_argument("--disable-translate")
    chrome_options.add_argument("--disable-background-networking")
    chrome_options.add_argument("--disable-sync")
    chrome_options.add_argument("--disable-default-apps")
    chrome_options.add_argument("--mute-audio")
    chrome_options.add_argument("--no-first-run")
    chrome_options.add_argument("--ignore-certificate-errors")
    chrome_options.add_argument(
        "--user-agent=Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 "
        "(KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
    )
    
    if CHROME_BINARY_PATH:
        chrome_options.binary_location = CHROME_BINARY_PATH
    
    service = Service(executable_path=CHROME_DRIVER_PATH)
    driver = webdriver.Chrome(service=service, options=chrome_options)
    driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
    driver.set_script_timeout(PAGE_LOAD_TIMEOUT)
    
    return driver


def take_screenshot(url: str) -> str:
    """Take a screenshot of the given URL and return the local file path."""
    driver = None
    screenshot_id = str(uuid.uuid4())
    screenshot_path = os.path.join(TEMP_DIR, f"{screenshot_id}_full.png")
    thumbnail_path = os.path.join(TEMP_DIR, f"{screenshot_id}_thumb.png")
    
    try:
        driver = create_chrome_driver()
        logger.info(f"Navigating to URL: {url}")
        
        driver.get(url)
        
        # Wait for page to be ready
        WebDriverWait(driver, PAGE_LOAD_TIMEOUT).until(
            lambda d: d.execute_script("return document.readyState") == "complete"
        )
        
        # Additional wait for dynamic content
        time.sleep(2)
        
        # Take screenshot
        driver.save_screenshot(screenshot_path)
        logger.info(f"Screenshot saved: {screenshot_path}")
        
        # Generate thumbnail
        create_thumbnail(screenshot_path, thumbnail_path)
        logger.info(f"Thumbnail created: {thumbnail_path}")
        
        return thumbnail_path
        
    except Exception as e:
        logger.error(f"Error taking screenshot of {url}: {e}")
        raise
    finally:
        if driver:
            try:
                driver.quit()
            except Exception:
                pass
        # Clean up full screenshot
        if os.path.exists(screenshot_path):
            os.remove(screenshot_path)


def create_thumbnail(input_path: str, output_path: str):
    """Create a thumbnail from the full screenshot."""
    with Image.open(input_path) as img:
        # Crop to the viewport area first (top portion)
        width, height = img.size
        crop_height = min(height, int(width * THUMBNAIL_HEIGHT / THUMBNAIL_WIDTH))
        img_cropped = img.crop((0, 0, width, crop_height))
        
        # Resize to thumbnail dimensions
        img_cropped.thumbnail((THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT), Image.LANCZOS)
        
        # Save as optimized PNG
        img_cropped.save(output_path, "PNG", optimize=True)


def upload_to_s3(file_path: str, url: str) -> tuple[str, str]:
    """Upload the thumbnail to S3 and return the public URL and S3 key."""
    url_hash = generate_url_hash(url)
    timestamp = datetime.utcnow().strftime("%Y%m%d")
    s3_key = f"{S3_PREFIX}{timestamp}/{url_hash}.png"
    
    try:
        s3_client.upload_file(
            file_path,
            S3_BUCKET,
            s3_key,
            ExtraArgs={
                "ContentType": "image/png",
                "CacheControl": "public, max-age=86400",
                "Metadata": {
                    "source-url": url[:256],  # Truncate for metadata limits
                    "created-at": datetime.utcnow().isoformat(),
                },
            },
        )
        
        s3_url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{s3_key}"
        logger.info(f"Uploaded to S3: {s3_url}")
        
        return s3_url, s3_key
        
    except Exception as e:
        logger.error(f"Error uploading to S3: {e}")
        raise


def cleanup_temp_file(file_path: str):
    """Remove temporary file."""
    try:
        if file_path and os.path.exists(file_path):
            os.remove(file_path)
    except OSError as e:
        logger.warning(f"Error cleaning up temp file {file_path}: {e}")


def authenticate_request():
    """Validate API key if configured."""
    if not API_KEY:
        return True
    
    provided_key = request.headers.get("X-API-Key", "")
    return provided_key == API_KEY


@app.route("/health", methods=["GET"])
def health_check():
    """Health check endpoint."""
    health = {
        "status": "healthy",
        "timestamp": datetime.utcnow().isoformat(),
        "redis_connected": REDIS_AVAILABLE,
    }
    
    # Check S3 connectivity
    try:
        s3_client.head_bucket(Bucket=S3_BUCKET)
        health["s3_connected"] = True
    except Exception:
        health["s3_connected"] = False
        health["status"] = "degraded"
    
    status_code = 200 if health["status"] == "healthy" else 503
    return jsonify(health), status_code


@app.route("/screenshot", methods=["POST"])
def screenshot():
    """
    Take a screenshot of the provided URL and return a thumbnail.
    
    Request body:
    {
        "url": "https://example.com",
        "force_refresh": false  (optional)
    }
    
    Response:
    {
        "success": true,
        "url": "https://example.com",
        "thumbnail_url": "https://bucket.s3.region.amazonaws.com/...",
        "cached": false,
        "timestamp": "2024-01-01T00:00:00"
    }
    """
    # Authentication
    if not authenticate_request():
        return jsonify({"success": False, "error": "Unauthorized"}), 401
    
    # Parse request
    data = request.get_json()
    if not data:
        return jsonify({"success": False, "error": "Request body must be JSON"}), 400
    
    url = data.get("url", "").strip()
    force_refresh = data.get("force_refresh", False)
    
    # Validate URL
    is_valid, error_msg = validate_url(url)
    if not is_valid:
        return jsonify({"success": False, "error": error_msg}), 400
    
    url_hash = generate_url_hash(url)
    
    # Check cache unless force refresh is requested
    if not force_refresh:
        cached_url = get_cached_screenshot(url_hash)
        if cached_url:
            return jsonify({
                "success": True,
                "url": url,
                "thumbnail_url": cached_url,
                "cached": True,
                "timestamp": datetime.utcnow().isoformat(),
            })
    
    # Take screenshot
    thumbnail_path = None
    try:
        thumbnail_path = take_screenshot(url)
        
        # Upload to S3
        s3_url, s3_key = upload_to_s3(thumbnail_path, url)
        
        # Cache the result
        set_cached_screenshot(url_hash, s3_url, s3_key)
        
        return jsonify({
            "success": True,
            "url": url,
            "thumbnail_url": s3_url,
            "cached": False,
            "timestamp": datetime.utcnow().isoformat(),
        })
        
    except Exception as e:
        logger.error(f"Screenshot generation failed for {url}: {e}")
        return jsonify({
            "success": False,
            "error": "Failed to generate screenshot",
            "details": str(e),
        }), 500
    finally:
        cleanup_temp_file(thumbnail_path)


@app.route("/screenshot/batch", methods=["POST"])
def batch_screenshot():
    """
    Take screenshots of multiple URLs.
    
    Request body:
    {
        "urls": ["https://example.com", "https://example.org"],
        "force_refresh": false
    }
    """
    if not authenticate_request():
        return jsonify({"success": False, "error": "Unauthorized"}), 401
    
    data = request.get_json()
    if not data:
        return jsonify({"success": False, "error": "Request body must be JSON"}), 400
    
    urls = data.get("urls", [])
    force_refresh = data.get("force_refresh", False)
    
    if not urls:
        return jsonify({"success": False, "error": "At least one URL is required"}), 400
    
    if len(urls) > 10:
        return jsonify({"success": False, "error": "Maximum 10 URLs per batch request"}), 400
    
    results = []
    
    for url in urls:
        url = url.strip()
        is_valid, error_msg = validate_url(url)
        
        if not is_valid:
            results.append({
                "url": url,
                "success": False,
                "error": error_msg,
            })
            continue
        
        url_hash = generate_url_hash(url)
        
        # Check cache
        if not force_refresh:
            cached_url = get_cached_screenshot(url_hash)
            if cached_url:
                results.append({
                    "url": url,
                    "success": True,
                    "thumbnail_url": cached_url,
                    "cached": True,
                })
                continue
        
        thumbnail_path = None
        try:
            thumbnail_path = take_screenshot(url)
            s3_url, s3_key = upload_to_s3(thumbnail_path, url)
            set_cached_screenshot(url_hash, s3_url, s3_key)
            
            results.append({
                "url": url,
                "success": True,
                "thumbnail_url": s3_url,
                "cached": False,
            })
        except Exception as e:
            logger.error(f"Batch screenshot failed for {url}: {e}")
            results.append({
                "url": url,
                "success": False,
                "error": str(e),
            })
        finally:
            cleanup_temp_file(thumbnail_path)
    
    return jsonify({
        "success": True,
        "results": results,
        "total": len(results),
        "successful": sum(1 for r in results if r.get("success")),
        "failed": sum(1 for r in results if not r.get("success")),
        "timestamp": datetime.utcnow().isoformat(),
    })


@app.route("/screenshot/presigned", methods=["POST"])
def get_presigned_url():
    """
    Get a presigned URL for an existing screenshot.
    Useful when S3 objects are private.
    """
    if not authenticate_request():
        return jsonify({"success": False, "error": "Unauthorized"}), 401
    
    data = request.get_json()
    if not data:
        return jsonify({"success": False, "error": "Request body must be JSON"}), 400
    
    url = data.get("url", "").strip()
    expiration = data.get("expiration", 3600)  # Default 1 hour
    
    is_valid, error_msg = validate_url(url)
    if not is_valid:
        return jsonify({"success": False, "error": error_msg}), 400
    
    url_hash = generate_url_hash(url)
    
    if REDIS_AVAILABLE:
        s3_key = redis_client.get(f"screenshot_key:{url_hash}")
        if s3_key:
            try:
                presigned_url = s3_client.generate_presigned_url(
                    "get_object",
                    Params={"Bucket": S3_BUCKET, "Key": s3_key},
                    ExpiresIn=min(expiration, 86400),  # Cap at 24 hours
                )
                return jsonify({
                    "success": True,
                    "url": url,
                    "presigned_url": presigned_url,
                    "expires_in": min(expiration, 86400),
                })
            except Exception as e:
                logger.error(f"Error generating presigned URL: {e}")
    
    return jsonify({
        "success": False,
        "error": "Screenshot not found. Please generate it first.",
    }), 404


@app.route("/cache/invalidate", methods=["POST"])
def invalidate_cache():
    """Invalidate cached screenshot for a URL."""
    if not authenticate_request():
        return jsonify({"success": False, "error": "Unauthorized"}), 401
    
    data = request.get_json()
    if not data:
        return jsonify({"success": False, "error": "Request body must be JSON"}), 400
    
    url = data.get("url", "").strip()
    delete_s3 = data.get("delete_from_s3", False)
    
    if not url:
        return jsonify({"success": False, "error": "URL is required"}), 400
    
    url_hash = generate_url_hash(url)
    
    if REDIS_AVAILABLE:
        s3_key = redis_client.get(f"screenshot_key:{url_hash}")
        
        # Delete from cache
        redis_client.delete(f"screenshot:{url_hash}")
        redis_client.delete(f"screenshot_key:{url_hash}")
        
        # Optionally delete from S3
        if delete_s3 and s3_key:
            try:
                s3_client.delete_object(Bucket=S3_BUCKET, Key=s3_key)
                logger.info(f"Deleted S3 object: {s3_key}")
            except Exception as e:
                logger.error(f"Error deleting S3 object: {e}")
    
    return jsonify({
        "success": True,
        "message": "Cache invalidated",
        "url": url,
    })


