def setup_s3_bucket():
    """Create S3 bucket if it doesn't exist and configure it."""
    try:
        s3_client.head_bucket(Bucket=S3_BUCKET)
        logger.info(f"S3 bucket '{S3_BUCKET}' exists")
    except s3_client.exceptions.ClientError as e:
        error_code = e.response["Error"]["Code"]
        if error_code == "404":
            logger.info(f"Creating S3 bucket: {S3_BUCKET}")
            create_params = {"Bucket": S3_BUCKET}
            if AWS_REGION != "us-east-1":
                create_params["CreateBucketConfiguration"] = {
                    "LocationConstraint": AWS_REGION
                }
            s3_client.create_bucket(**create_params)
            
            # Enable versioning
            s3_client.put_bucket_versioning(
                Bucket=S3_BUCKET,
                VersioningConfiguration={"Status": "Enabled"},
            )
            
            # Set lifecycle policy to clean up old screenshots
            s3_client.put_bucket_lifecycle_configuration(
                Bucket=S3_BUCKET,
                LifecycleConfiguration={
                    "Rules": [
                        {
                            "ID": "cleanup-old-screenshots",
                            "Status": "Enabled",
                            "Filter": {"Prefix": S3_PREFIX},
                            "Expiration": {"Days": 30},
                            "NoncurrentVersionExpiration": {"NoncurrentDays": 7},
                        }
                    ]
                },
            )
            logger.info(f"S3 bucket '{S3_BUCKET}' created with lifecycle policy")
        else:
            logger.error(f"Error checking S3 bucket: {e}")
            raise


if __name__ == "__main__":
    setup_s3_bucket()
    
    port = int(os.environ.get("PORT", 5000))
    debug = os.environ.get("FLASK_DEBUG", "false").lower() == "true"
    
    logger.info(f"Starting Screenshot Service on port {port}")
    logger.info(f"S3 Bucket: {S3_BUCKET}")
    logger.info(f"Redis Available: {REDIS_AVAILABLE}")
    logger.info(f"Thumbnail Size: {THUMBNAIL_WIDTH}x{THUMBNAIL_HEIGHT}")
    
    app.run(host="0.0.0.0", port=port, debug=debug)